class Solution:
    def minLength(self, s: str) -> int:
        changed = True
        while changed:
            changed = False
            i = 0
            while i < len(s) - 1:
                if s[i:i+2] == "AB" or s[i:i+2] == "CD":
                    s = s[:i] + s[i+2:]
                    changed = True
                    break  # Restart scanning from the beginning
                i += 1
        return len(s)
